mapper.select:
select * from lkt_integral_goods a

    


    a.sort ${sort_sort},

LIMIT #{pageStart},#{pageEnd}

SELECT g.*, a.id AS goodsId, if(a.volume is null,0,a.volume) volume, a.imgurl, a.product_title , a.subtitle, a.STATUS, a.s_type,a.initial FROM lkt_integral_goods g LEFT JOIN lkt_product_list a ON g.goods_id = a.id LEFT JOIN lkt_mch m ON a.mch_id = m.id
g.sort ${sort_sort},
LIMIT #{page},#{pageSize}

select b.*,a.product_title,a.imgurl,a.product_class,mch.name mchName,a.initial,class.pname,brand.brand_name,c.attribute,c.id attrId,c.img,c.price,c.num attrNum from lkt_integral_goods as b left join lkt_product_list as a on b.goods_id=a.id left join lkt_product_class class on class.cid = substring_index(substring_index(a.product_class, '-', 2), '-', -1) left join lkt_configure AS c ON a.id = c.pid and b.attr_id = c.id left join lkt_brand_class brand on brand.brand_id=a.brand_id left join lkt_mch mch on mch.id = a.mch_id
b.sort ${sort_sort},
LIMIT #{pageStart},#{pageEnd}

select b.integral, b.money, b.status, b.goods_id, a.product_title,a.imgurl,a.product_class,a.initial,class.pname, c.attribute,c.id attrId,c.img,c.price,c.num attrNum,o.sNo, o.add_time, o.remark, u.user_id, u.mobile from lkt_integral_goods as b left join lkt_product_list as a on b.goods_id=a.id left join lkt_product_class class on class.cid = substring_index(substring_index(a.product_class, '-', 2), '-', -1) left join lkt_configure AS c ON a.id = c.pid and b.attr_id = c.id right join lkt_order_details as details on details.p_id = b.id right join lkt_order as o on o.sNo = details.r_sNo right join lkt_user as u on o.user_id = u.user_id
and b.id = #{goodsId} and b.store_id = #{storeId} and o.otype = 'IN'
LIMIT #{pageStart},#{pageEnd}
